      this.eventNewName = null;
    },
    eventCloseNewEvent() {
      this.eventSeletorDialog = true;
      this.eventNewDialog = false;
    },
    saveNewEvent() {
      return;
      this.eventNewLoading = true;

      axios.post(Vue.preUrl + "/newCg", {
