        this.eventNewLoading = false;
        setTimeout(() => { this.eventNewError = false}, 1500);

        console.log(error);
        this.$store.commit("DEFINE_SNACK", {
          active: true,
          error: true,
          text: error,
          type: "error"
        });
        if (error.response.status === 401) {
          this.loginDialog = true;
        }
      })
